/**
 * Encrypt a FlowFrame using the full Lacey cipher variant:
 * 1. Structural rotating half-helix cipher (steganographic confusion).
 * 2. Syzygy smush (ChaCha20-Poly1305 AEAD via WASM).
 */
export async function laceyEncryptFrame(
  frame: Uint8Array,
  key: RotatingHelixKey,
  keyPhrase: string
): Promise<Uint8Array> {
  try {
    const structural = rotatingHelixEncryptFrame(frame, key);
    const mod = await loadBitwiseModule();
    if (mod.syzygySmush) return mod.syzygySmush(structural, keyPhrase);
    if (mod.loadBitwiseClient) return (await mod.loadBitwiseClient()).syzygySmush(structural, keyPhrase);
    return (mod as any).default.syzygySmush(structural, keyPhrase);

  } catch (error) {
    throw new Error(`[laceyEncryptFrame] ${error instanceof Error ? error.message : String(error)}`);
  }
}

/**
 * Decrypt a FlowFrame using the full Lacey cipher variant:
 * 1. Syzygy unsmush (ChaCha20-Poly1305 AEAD via WASM).
 * 2. Structural rotating half-helix cipher (un-rotate and un-permute).
 */
export async function laceyDecryptFrame(
  encrypted: Uint8Array,
  key: RotatingHelixKey,
  keyPhrase: string,
  originalLength: number
): Promise<Uint8Array> {
  try {
    const mod = await loadBitwiseModule();
    let structural: Uint8Array;
    if (mod.syzygyUnsmush) {
      structural = await mod.syzygyUnsmush(encrypted, keyPhrase, originalLength);
    } else if (mod.loadBitwiseClient) {
      structural = await (await mod.loadBitwiseClient()).syzygyUnsmush(encrypted, keyPhrase, originalLength);
    } else {
      structural = await (mod as any).default.syzygyUnsmush(encrypted, keyPhrase, originalLength);
    }
    return rotatingHelixDecryptFrame(structural, key);

  } catch (error) {
    throw new Error(`[laceyDecryptFrame] ${error instanceof Error ? error.message : String(error)}`);
  }
}

/**
 * Encrypt an entire multi-frame stream using the full Lacey cipher variant.
 */
export async function laceyEncryptStream(
  stream: Uint8Array,
  key: RotatingHelixKey,
  keyPhrase: string
): Promise<Uint8Array> {
  try {
    const structural = rotatingHelixEncryptStream(stream, key);
    const mod = await loadBitwiseModule();
    if (mod.syzygySmush) return mod.syzygySmush(structural, keyPhrase);
    if (mod.loadBitwiseClient) return (await mod.loadBitwiseClient()).syzygySmush(structural, keyPhrase);
    return (mod as any).default.syzygySmush(structural, keyPhrase);

  } catch (error) {
    throw new Error(`[laceyEncryptStream] ${error instanceof Error ? error.message : String(error)}`);
  }
}

/**
 * Decrypt an entire multi-frame stream using the full Lacey cipher variant.
 */
export async function laceyDecryptStream(
  encrypted: Uint8Array,
  key: RotatingHelixKey,
  keyPhrase: string,
  originalLength: number
): Promise<Uint8Array> {
  try {
    const mod = await loadBitwiseModule();
    let structural: Uint8Array;
    if (mod.syzygyUnsmush) {
      structural = await mod.syzygyUnsmush(encrypted, keyPhrase, originalLength);
    } else if (mod.loadBitwiseClient) {
      structural = await (await mod.loadBitwiseClient()).syzygyUnsmush(encrypted, keyPhrase, originalLength);
    } else {
      structural = await (mod as any).default.syzygyUnsmush(encrypted, keyPhrase, originalLength);
    }
    return rotatingHelixDecryptStream(structural, key);

  } catch (error) {
    throw new Error(`[laceyDecryptStream] ${error instanceof Error ? error.message : String(error)}`);
  }
}
